class TrieNode:
    def __init__(self):
        self.children = [None]*26
        self.endOfWord = False

    def insert(self, word):
        node = self
        for c in word:
            if node.children[ord(c) - ord('a')] is None:
                node.children[ord(c) - ord('a')] = TrieNode()
            node = node.children[ord(c) - ord('a')]
        node.endOfWord = True

class Trie:
    def __init__(self):
        self.root = TrieNode()


def main():
    trie = Trie()
    s = input().split('\n')
    for i in range(1, len(s), 2):
        trie.root.insert(s[i])
    target = input().split('\n')[-1]
    print(trie.root.insert(target))
